// Import dependencies
import { EventEmitter } from 'events';
import { createHash } from 'crypto';

// Configuration constants
const CONFIG = {
  MAX_CAPACITY: 10000,
  DEFAULT_TIMEOUT: 5000,
  RETRY_ATTEMPTS: 3,
  LOG_LEVEL: 'info'
};

// Event emitter for inventory events
class InventoryManager extends EventEmitter {
  constructor(options = {}) {
    super();
    this.items = new Map();
    this.locations = new Map();
    this.transactions = [];
    this.capacity = options.capacity || CONFIG.MAX_CAPACITY;
    this.timeout = options.timeout || CONFIG.DEFAULT_TIMEOUT;
    this.retryAttempts = options.retryAttempts || CONFIG.RETRY_ATTEMPTS;
    this.logLevel = options.logLevel || CONFIG.LOG_LEVEL;
  }

  // Add new item to inventory
  addItem(item) {
    if (!item.id || !item.name) {
      throw new Error('Item must have id and name');
    }
    if (this.items.size >= this.capacity) {
      throw new Error('Inventory capacity exceeded');
    }
    this.items.set(item.id, { ...item, timestamp: Date.now() });
    this.emit('itemAdded', item);
    return item;
  }

  // Remove item from inventory
  removeItem(itemId) {
    const item = this.items.get(itemId);
    if (!item) {
      throw new Error('Item not found');
    }
    this.items.delete(itemId);
    this.emit('itemRemoved', item);
    return item;
  }

  // Update item quantity
  updateQuantity(itemId, quantity) {
    const item = this.items.get(itemId);
    if (!item) {
      throw new Error('Item not found');
    }
    item.quantity = quantity;
    this.emit('quantityUpdated', { itemId, quantity });
    return item;
  }

  // Get item by ID
  getItem(itemId) {
    return this.items.get(itemId);
  }

  // Get all items
  getAllItems() {
    return Array.from(this.items.values());
  }

  // Transfer item between locations
  transferItem(itemId, fromLocation, toLocation) {
    const item = this.items.get(itemId);
    if (!item) {
      throw new Error('Item not found');
    }
    const transaction = {
      itemId,
      fromLocation,
      toLocation,
      timestamp: Date.now()
    };
    this.transactions.push(transaction);
    item.location = toLocation;
    this.emit('itemTransferred', transaction);
    return transaction;
  }

  // Generate inventory report
  generateReport() {
    const report = {
      totalItems: this.items.size,
      totalQuantity: Array.from(this.items.values()).reduce((sum, item) => sum + item.quantity, 0),
      transactions: this.transactions.length,
      locations: this.locations.size,
      timestamp: Date.now()
    };
    this.emit('reportGenerated', report);
    return report;
  }

  // Log message based on log level
  log(level, message) {
    const levels = { debug: 0, info: 1, warn: 2, error: 3 };
    if (levels[level] >= levels[this.logLevel]) {
      console.log(`[${level.toUpperCase()}] ${message}`);
    }
  }
}

// Location management class
class LocationManager {
  constructor() {
    this.locations = new Map();
  }

  addLocation(location) {
    if (!location.id || !location.name) {
      throw new Error('Location must have id and name');
    }
    this.locations.set(location.id, location);
    return location;
  }

  getLocation(locationId) {
    return this.locations.get(locationId);
  }

  removeLocation(locationId) {
    return this.locations.delete(locationId);
  }

  getAllLocations() {
    return Array.from(this.locations.values());
  }
}

// Transaction logging system
class TransactionLogger {
  constructor() {
    this.logs = [];
  }

  log(transaction) {
    const entry = {
      ...transaction,
      id: createHash('sha256').update(JSON.stringify(transaction)).digest('hex'),
      timestamp: Date.now()
    };
    this.logs.push(entry);
    return entry;
  }

  getLogs() {
    return this.logs;
  }

  clear() {
    this.logs = [];
  }
}

// Export modules
module.exports = {
  InventoryManager,
  LocationManager,
  TransactionLogger,
  CONFIG
};
